  // 섹션 진입: 메인 물감은 그대로 두고, 그 위로 대표색이 확 퍼져 덮임
  function diveInto(node) {
    if (isOpen || !node) return;
    isOpen = true;
    if (hotNode) { hotNode.classList.remove('hot'); hotNode = null; }
    const key = node.dataset.key;
    const pal = PALETTES[key];
    targetBg = MAIN_BG;   // 배경은 흰색 유지 (기본화면 색이 가장자리에 비침)

    // 클릭한 노드 위치에서 대표색이 확 퍼져나감
    const rect = node.getBoundingClientRect();
    const ox = (rect.left + rect.width/2) / W;
    const oy = (rect.top + rect.height/2) / H;
    diveOrigin = { x: ox, y: oy };   // back 시 이 자리로 되돌아감

    // 섹션 팔레트 배치 좌표 (덮는 영역 안에 흩뿌림)
    const layout = [
      { x: 0.28, y: 0.42 }, { x: 0.66, y: 0.36 },
      { x: 0.5, y: 0.66 },  { x: 0.8, y: 0.6 },
    ];
    // 메인 물감(blobs)은 그대로 두고, 대표색 덮개 물감을 위에 얹음
    overlayBlobs = pal.map((color, i) => {
      const spot = layout[i] || { x: Math.random(), y: Math.random() };
      const b = makeBlob(ox, oy, MAIN[key], 40, 30 + Math.random()*16);
      b.baseX = spot.x; b.baseY = spot.y;
      b.x = ox * W; b.y = oy * H;
      b.tr = 340 + Math.random()*110;   // 크게 퍼져서 화면을 덮음
      b.targetColor = color;
      return b;
    });

    // UI 전환
    nodesWrap.classList.add('nodes-hidden');
    hud.style.opacity = '0';
    hint.style.opacity = '0';
    const wxE = document.getElementById('wx');
    if (wxE) wxE.style.opacity = '0';
    const sndWrap = document.querySelector('.sound-wrap');
    if (sndWrap) { sndWrap.style.opacity = '0'; sndWrap.style.pointerEvents = 'none'; }
    const cue = document.getElementById('scrollCue');
    if (cue) cue.style.opacity = '0';
    setTimeout(() => {
      sections.forEach(s => s.classList.toggle('active', s.dataset.key === key));
      backBtn.classList.add('show');
    }, 350);
  }

  function backToPalette() {
    isOpen = false;
    exitAccum = 0;
    window.scrollTo(0, 0);   // 다이브는 최상단에서만 일어나므로 위치 고정
    targetBg = MAIN_BG;
    sections.forEach(s => s.classList.remove('active'));
    backBtn.classList.remove('show');
    const cue = document.getElementById('scrollCue');
    if (cue && window.scrollY < 60) cue.style.opacity = '1';

    // 덮개 물감을 처음 들어온 지점으로 천천히 모으고, 투명도로 빠르게 사라짐
    overlayBlobs.forEach(b => {
      b.baseX = diveOrigin.x; b.baseY = diveOrigin.y;
      b.drift = 0;
      // 반경은 크게 유지 (모이는 동안 투명도가 먼저 사라짐)
      b.fading = true;
    });

    nodesWrap.classList.remove('nodes-hidden');
    hud.style.opacity = '1';
    hint.style.opacity = '1';
    const wxE = document.getElementById('wx');
    if (wxE && window.scrollY < 60) wxE.style.opacity = '1';
    const sndWrap = document.querySelector('.sound-wrap');
    if (sndWrap && window.scrollY < 60) { sndWrap.style.opacity = '1'; sndWrap.style.pointerEvents = 'auto'; }
  }

