    const rgb = color.split(',').map(n => parseInt(n.trim(), 10));
    const factor = 0.65;   // 모든 색 동일 비율 → 색 구분 유지
    const dk = rgb.map(c => Math.round(c * factor));
    detail.style.background = `rgb(${dk[0]},${dk[1]},${dk[2]})`;
    // 클릭 지점 x에서, 상단쪽을 기준으로 원형이 퍼짐 (제목이 먼저 드러나게)
    const rect = sub.getBoundingClientRect();
    const cx = rect.left + rect.width/2, cy = rect.top + rect.height/2;
    const oy = H * 0.05;   // 확장 원점 y: 화면 맨 위 (제목이 먼저 드러나게)
    detail.style.transition = 'none';
    detail.style.clipPath = `circle(0px at ${cx}px ${cy}px)`;
    detail.classList.add('open');
